  // src/shout_out_swapper/services/myFictions.js
  var logger15 = log.scope("myFictions");
  function parseFictionsFromHtml(html) {
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, "text/html");
    const fictions = [];
    const fictionElements = doc.querySelectorAll(".fiction[data-fiction-id]");
    for (const el of fictionElements) {
      const fictionId = el.dataset.fictionId;
      const title = el.dataset.title || "";
      const coverImg = el.querySelector('img[data-type="cover"]');
      const coverUrl = coverImg?.src || "";
      if (fictionId) {
        fictions.push({
          fictionId,
          title,
          coverUrl
        });
      }
    }
    return fictions;
  }
  async function fetchMyFictions() {
    try {
      const response = await fetch("https://www.royalroad.com/author-dashboard", {
        credentials: "include"
      });
      if (!response.ok) {
        logger15.warn("Failed to fetch author-dashboard", { status: response.status });
        return [];
      }
      const html = await response.text();
      const fictions = parseFictionsFromHtml(html);
      logger15.info("Fetched fictions from author-dashboard", { count: fictions.length });
      return fictions;
    } catch (err) {
      logger15.error("Error fetching author-dashboard", err);
      return [];
    }
  }
  async function syncMyFictions() {
    let existingFictions = await getAll("myFictions") || [];
    if (existingFictions.length > 0) {
      logger15.info("Using cached fictions from DB", { count: existingFictions.length });
      return existingFictions;
    }
    const fictions = await fetchMyFictions();
    if (fictions.length === 0) {
      logger15.info("No fictions found");
      return [];
    }
    for (const fiction of fictions) {
      const existing = existingFictions.find((f5) => f5.fictionId === fiction.fictionId);
      if (existing) {
        await save("myFictions", {
          ...existing,
          title: fiction.title,
          coverUrl: fiction.coverUrl
        });
      } else {
        await save("myFictions", fiction);
      }
    }
    logger15.info("Synced fictions to DB", { count: fictions.length });
    return getAll("myFictions");
  }

  // src/shout_out_swapper/ui/layout/Layout.jsx
