  var Overlay_default = "/* Base overlay styles */\n/* Creates a fixed fullscreen backdrop with centered content */\n\n.rr-overlay {\n  position: fixed !important;\n  top: 0 !important;\n  left: 0 !important;\n  right: 0 !important;\n  bottom: 0 !important;\n  width: 100vw !important;\n  height: 100vh !important;\n  background: rgba(0, 0, 0, 0.5) !important;\n  display: none !important;\n  align-items: center !important;\n  justify-content: center !important;\n  z-index: 10000 !important;\n  margin: 0 !important;\n  padding: 0 !important;\n}\n\n.rr-overlay.rr-overlay-open {\n  display: flex !important;\n}\n\n.rr-overlay-container {\n  max-height: 90vh;\n  max-width: 90vw;\n}\n";

  // src/common/ui/modal/Modal.css
  var Modal_default = `/* Modal styles - Royal Road theme compatible */

/* Modal base - inherits background from RR's .card class */
.rr-modal {
  width: 90%;
  max-width: 900px;
  display: flex;
  flex-direction: column;
  /* Let native form controls (select option dropdowns in particular) match
     the host page's theme instead of defaulting to white on a dark page. */
  color-scheme: light dark;
}

.rr-modal select,
.rr-modal input,
.rr-modal textarea {
  color-scheme: inherit;
}

.rr-modal-small {
  width: 400px;
}

.rr-modal-medium {
  width: 600px;
}

.rr-modal-large {
  width: 800px;
}

.rr-modal-xlarge {
  width: 95%;
  max-width: 1100px;
}

/* Settings: fixed width and height so the modal doesn't reflow when the
   active tab changes content length. The body itself doesn't scroll \u2014 the
   tab content pane (.rr-settings-form) handles its own overflow. */
.rr-modal-settings {
  width: 600px;
  max-width: calc(100vw - 2rem);
}

.rr-modal-settings .rr-modal-body {
  overflow: hidden;
}

/* Header */
.rr-modal-header {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 1.25rem;
  border-bottom: 1px solid rgba(128, 128, 128, 0.15);
}

.rr-modal-header .card-title {
  margin: 0;
}

.rr-modal-title {
  font-size: 1.1rem;
  font-weight: 600;
}

.rr-modal-close {
  background: transparent;
  border: none;
  font-size: 1.5rem;
  line-height: 1;
  padding: 0.25rem 0.5rem;
  color: rgba(128, 128, 128, 0.7);
  cursor: pointer;
  transition: color 0.15s;
}

.rr-modal-close:hover {
  color: inherit;
}

/* Body */
.rr-modal .rr-modal-body {
  overflow: visible;
}

/* Footer */
.rr-modal-footer {
  display: flex;
  justify-content: flex-end;
  gap: 0.5rem;
}

/* Scrollbar for modal body */
.rr-modal-body::-webkit-scrollbar {
  width: 6px;
}

.rr-modal-body::-webkit-scrollbar-track {
  background: transparent;
}

.rr-modal-body::-webkit-scrollbar-thumb {
  background: rgba(128, 128, 128, 0.3);
  border-radius: 3px;
}

.rr-modal-body::-webkit-scrollbar-thumb:hover {
  background: rgba(128, 128, 128, 0.5);
}

/* Form labels inside modal */
.rr-modal label,
.rr-label,
.rr-modal-label {
  display: block;
  font-size: 0.85rem;
  font-weight: 500;
  margin-bottom: 0.5rem;
  color: rgba(128, 128, 128, 0.8);
}

/* Beat RR's Bootstrap/Metronic form-control styling (which hardcodes a
   white background) with !important on the closed-state colours. The
   option dropdown (drawn by the OS) is handled via color-scheme above. */
.rr-modal input[type="text"],
.rr-modal input[type="date"],
.rr-modal textarea,
.rr-modal select {
  width: 100%;
  padding: 0.5rem 0.75rem;
  background: rgba(128, 128, 128, 0.08) !important;
  border: 1px solid rgba(128, 128, 128, 0.15) !important;
  border-radius: 4px;
  color: inherit !important;
  font-size: 0.9rem;
  transition: border-color 0.15s, background-color 0.15s;
}

.rr-modal select option {
  /* Inherit the page/modal background so the option list matches when the
     browser supports themed controls. Native dropdowns on some systems
     still paint white \u2014 that's a browser limitation. */
  background-color: inherit;
  color: inherit;
}

/* Fully-styled select replacement (ThemedSelect component). Used when the
   native OS-drawn <select> option panel can't be themed. */
.rr-themed-select {
  position: relative;
  width: 100%;
}

.rr-themed-select-btn {
  display: flex !important;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  text-align: left;
  cursor: pointer;
}

.rr-themed-select-btn[disabled] {
  cursor: not-allowed;
  opacity: 0.6;
}

.rr-themed-select-value {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.rr-themed-select-caret {
  opacity: 0.6;
  margin-left: 0.5rem;
  flex-shrink: 0;
}

.rr-themed-select-menu {
  position: absolute;
  top: calc(100% + 4px);
  left: 0;
  right: 0;
  z-index: 100;
  list-style: none;
  margin: 0;
  padding: 0.25rem 0;
  background: var(--rr-card-bg, #2b2b2b);
  color: inherit;
  border: 1px solid rgba(128, 128, 128, 0.3);
  border-radius: 4px;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.35);
  max-height: 260px;
  overflow-y: auto;
}

.rr-themed-select-option {
  padding: 0.4rem 0.75rem;
  cursor: pointer;
  font-size: 0.85rem;
  color: inherit;
  background: transparent;
}

.rr-themed-select-option:hover {
  background: rgba(128, 128, 128, 0.15);
}

.rr-themed-select-option.is-active {
  background: rgba(51, 122, 183, 0.2);
  color: #337ab7;
  font-weight: 500;
}

.rr-modal input:focus,
.rr-modal textarea:focus,
.rr-modal select:focus {
  outline: none;
  border-color: rgba(128, 128, 128, 0.4) !important;
  background: rgba(128, 128, 128, 0.12) !important;
}

.rr-modal textarea {
  resize: vertical;
  min-height: 100px;
}

/* Form groups */
.rr-modal .form-group {
  margin-bottom: 1rem;
}

.rr-modal .form-group:last-child {
  margin-bottom: 0;
}

/* Responsive */
@media (max-width: 768px) {
  .rr-modal,
  .rr-modal-small,
  .rr-modal-medium,
  .rr-modal-large,
  .rr-modal-xlarge {
    width: 95vw;
    max-height: 90vh;
  }
}
`;

